#include <bits/stdc++.h>
using namespace std;
int n,s[100005][2],ans=0;
bool check(int x){
    while(x){
        if(x%10==0 || x%10==2 || x%10==4)
            return true;
        x/=10;
    }
    return false;
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)
        cin>>s[i][0];
    for(int i=1;i<=n;i++)
        cin>>s[i][1];
    int w=0;
    for(int i=1;i<=n;i++)
        if(check(s[i][w]))
            ans++,w=(w+1)%2;
    cout<<ans;
    return 0;
}
